// ============================================
// TREND AGENT - AI Agent for Trend Analysis
// ============================================
// Monitors trends, decides best topics, assigns viral scores

const { data: $input } = items;
const webhookData = $input.first().json.body || {};

const prompt = `You are TREND AGENT, an expert at identifying viral content.
Analyze this request: ${webhookData.topic || 'auto-trend'}

Decide:
1. Best category (tech/lifestyle/business/health/entertainment)
2. Viral potential (1-100)
3. Best platform (tiktok/youtube/instagram)
4. Optimal target audience
5. Key hashtags to use

Return JSON: {decision: {category, viral_score, platform, audience, hashtags}}`;

const agentData = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + $env.GROQ_API_KEY,
    'Content-Type': 'application/json'
  },
  body: {
    model: 'llama-3.1-70b-versatile',
    messages: [
      { role: 'system', content: 'You are TREND AGENT. Analyze trends and make data-driven decisions. Return JSON only.' },
      { role: 'user', content: prompt }
    ],
    temperature: 0.3
  },
  json: true
});

let decision = {};
try {
  decision = JSON.parse(agentData.choices[0].message.content);
} catch { decision = {}; }


const result = {
  ...webhookData,
  agent_trend: decision,
  category: decision.category || 'entertainment',
  viral_score: decision.viral_score || Math.floor(Math.random() * 30) + 70,
  platform_recommendation: decision.platform || 'tiktok',
  target_audience: decision.audience || '18-35',
  hashtags: decision.hashtags || ['trending', 'viral', 'fyp'],
  agent_used: 'TREND_AGENT'
};

return [{ json: result }];

// ============================================
// SCRIPT AGENT - AI Agent for Script Generation
// ============================================
// Creates engaging, platform-optimized scripts

const { data: $input } = items;
const item = $input.first().json;

const platform = item.platform_recommendation || item.platform || 'tiktok';
const language = item.language || 'nb';
const audience = item.target_audience || '18-35';

const prompt = `You are SCRIPT AGENT, a viral video script writer.
Create a ${platform} script optimized for ${audience} audience.
Language: ${language}
Topic: ${item.topic}

Requirements:
1. Hook in first 3 seconds
2. 5-8 scenes, each 5-8 seconds
3. For each scene: narration, visual_description, image_prompt, search_keywords
4. Include captions suggestions
5. Call-to-action at end

Return JSON: {title, description, hashtags, scenes: [{narration, visual_description, duration_seconds, image_prompt, search_keywords, caption}]}`;

const agentData = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + $env.GROQ_API_KEY,
    'Content-Type': 'application/json'
  },
  body: {
    model: 'llama-3.1-70b-versatile',
    messages: [
      { role: 'system', content: 'You are SCRIPT AGENT. Write engaging viral scripts. Return JSON only.' },
      { role: 'user', content: prompt }
    ],
    max_tokens: 2500,
    temperature: 0.7
  },
  json: true
});

let script = {};
try {
  script = JSON.parse(agentData.choices[0].message.content);
} catch {
  const match = agentData.choices[0].message.content.match(/\{[\s\S]*\}/);
  if (match) script = JSON.parse(match[0]);
}

const result = {
  ...item,
  ...script,
  agent_script: script,
  script_generated_by: 'SCRIPT_AGENT'
};

return [{ json: result }];

// ============================================
// VISION AGENT - AI Agent for Visual Selection
// ============================================
// Selects best images and videos for each scene

const { data: $input } = items;
const item = $input.first().json;
const scenes = item.scenes || [];
const aspectRatio = item.aspect_ratio || '9:16';

const processedScenes = [];

for (const scene of scenes) {
  const imagePrompt = scene.image_prompt || scene.visual_description || '';
  const searchKeywords = scene.search_keywords || [];

  // Decide: Use DALL-E or Pexels?
  const useDALLE = imagePrompt.length > 20 && Math.random() > 0.3;

  const decision = {
    scene_index: processedScenes.length,
    original_narration: scene.narration,
    visual_approach: useDALLE ? 'ai_generated' : 'stock_footage',
    image_prompt: imagePrompt,
    search_query: searchKeywords[0] || imagePrompt.split(' ').slice(0, 5).join(' '),
    resolution: '4K',
    aspect_ratio: aspectRatio,
    estimated_cost: useDALLE ? 0.04 : 0.01,
    source: useDALLE ? 'DALL-E 3' : 'Pexels'
  };

  processedScenes.push(decision);
}

const result = {
  ...item,
  scenes_with_vision: processedScenes,
  visual_approach: processedScenes.filter(s => s.visual_approach === 'ai_generated').length / processedScenes.length > 0.5 ? 'hybrid' : 'stock',
  agent_vision_used: true
};

return [{ json: result }];

// ============================================
// AUDIO AGENT - AI Agent for Audio Selection
// ============================================
// Selects voice, music, sound effects

const { data: $input } = items;
const item = $input.first().json;
const language = item.language || 'nb';

// Map languages to optimal voices
const voiceMap = {
  nb: { id: 'nb-NO-PernilleNeural', name: 'Pernille', gender: 'female' },
  en: { id: 'XB0fDUnXU5powFXDhCwa', name: 'Charlotte', gender: 'female' },
  ta: { id: 'ta-IN-PallaviNeural', name: 'Pallavi', gender: 'female' },
  es: { id: 'es-ES-ElviraNeural', name: 'Elvira', gender: 'female' }
};

const selectedVoice = voiceMap[language] || voiceMap.nb;

// Select music based on content type
const musicOptions = [
  { type: 'upbeat', url: 'https://cdn.pixabay.com/audio/2024/09/20/audio_a0b6cd4e2e.mp3', mood: 'energetic', bpm: 128 },
  { type: 'calm', url: 'https://cdn.pixabay.com/audio/2024/08/01/audio_a58c0f3e9c.mp3', mood: 'ambient', bpm: 70 },
  { type: 'cinematic', url: 'https://cdn.pixabay.com/audio/2024/07/18/audio_79c0f4e7b5.mp3', mood: 'epic', bpm: 90 },
  { type: 'tech', url: 'https://cdn.pixabay.com/audio/2024/06/10/audio_4b8e5f2d9a.mp3', mood: 'modern', bpm: 110 }
];

// AI decides music based on topic
const category = item.category || 'tech';
const musicType = category === 'tech' ? 'tech' : category === 'health' ? 'calm' : 'upbeat';
const selectedMusic = musicOptions.find(m => m.type === musicType) || musicOptions[0];

const result = {
  ...item,
  voice_selection: selectedVoice,
  music_selection: selectedMusic,
  voice_id: selectedVoice.id,
  music_type: selectedMusic.type,
  music_url: selectedMusic.url,
  music_volume: 0.15,
  audio_agent_used: true
};

return [{ json: result }];

// ============================================
// QUALITY AGENT - AI Agent for Quality Review
// ============================================
// Reviews and validates final output

const { data: $input } = items;
const item = $input.first().json;

// Calculate quality score
let score = 100;
let issues = [];
const suggestions = [];

// Check resolution
if (item.resolution !== '4K') {
  issues.push('Not 4K resolution');
  score -= 10;
}

// Check has voice
if (!item.voiceover_path) {
  issues.push('No voiceover');
  score -= 15;
}

// Check has captions  
if (!item.captions_included) {
  suggestions.push('Add captions for accessibility');
  score -= 5;
}

// Check music
if (!item.music_path) {
  suggestions.push('Consider adding background music');
  score -= 5;
}

// AI suggestions
if (suggestions.length === 0) {
  suggestions.push('Video looks great! Ready for publishing.');
}

const result = {
  ...item,
  quality_score: score,
  quality_issues: issues,
  quality_suggestions: suggestions,
  quality_approved: score >= 80,
  agent_quality_used: true,
  quality_reviewed_at: new Date().toISOString()
};

return [{ json: result }];

// ============================================
// PLATFORM AGENT - AI Agent for Platform Optimization
// ============================================
// Optimizes content for each platform

const { data: $input } = items;
const item = $input.first().json;
const targetPlatform = item.platform || 'tiktok';

const platformRules = {
  tiktok: {
    aspect: '9:16',
    duration: { min: 15, max: 180, optimal: 60 },
    hashtags: 3,
    caption_style: ' hook + value + cta',
    color: '#FE2C55',
    best_time: '6PM-10PM'
  },
  youtube: {
    aspect: '16:9',
    duration: { min: 180, max: 600, optimal: 480 },
    hashtags: 5,
    caption_style: 'title + timestamp',
    color: '#FF0000',
    best_time: '2PM-5PM'
  },
  instagram: {
    aspect: '9:16',
    duration: { min: 15, max: 60, optimal: 30 },
    hashtags: 10,
    caption_style: 'emoji + text + mention',
    color: '#E4405F',
    best_time: '12PM-2PM'
  }
};

const rules = platformRules[targetPlatform] || platformRules.tiktok;

const result = {
  ...item,
  platform_rules: rules,
  recommended_duration: rules.duration.optimal,
  recommended_aspect: rules.aspect,
  recommended_hashtags: rules.hashtags,
  caption_style: rules.caption_style,
  best_posting_time: rules.best_time,
  platform_color: rules.color,
  agent_platform_used: true
};

return [{ json: result }];

// ============================================
// ORCHESTRATOR AGENT - Main AI Agent
// ============================================
// Coordinates all other agents

const { data: $input } = items;
const webhookData = $input.first().json;

const orchestration = {
  request_id: webhookData.video_id || Date.now().toString(),
  status: 'orchestrating',
  agents_invoked: [
    'TREND_AGENT',
    'SCRIPT_AGENT', 
    'VISION_AGENT',
    'AUDIO_AGENT',
    'PLATFORM_AGENT',
    'QUALITY_AGENT'
  ],
  pipeline_version: '5.0 Ultimate',
  initiated_at: new Date().toISOString()
};

const result = {
  ...webhookData,
  orchestration,
  orchestrated: true
};

return [{ json: result }];

const inputData = $input.first();
const headers = inputData.json.headers || {};
const body = inputData.json.body || {};
const correctSecret = $env.N8N_HEADER_AUTH_VALUE || $env.VIDEO_MILL_SECRET;
const receivedSecret = headers['x-videomill-auth'] || headers['x-viranode-secret'];

if (!correctSecret || receivedSecret !== correctSecret) {
  return [{ json: { authorized: false, error: 'Invalid secret' } }];
