  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + $env.GROQ_API_KEY,
    'Content-Type': 'application/json'
  },
  body: {
    model: 'llama-3.1-8b-instant',
    messages: [{ role: 'user', content: prompt }],
    max_tokens: 3000,
    temperature: 0.4
  },
  json: true
});

const resp = data.choices?.[0]?.message?.content || '';
let topics = [];
try { topics = JSON.parse(resp); } catch {
  const m = resp.match(/\[[\s\S]*\]/);
  if (m) topics = JSON.parse(m[0]);
}

if (!topics.length) topics = [
  { title: "AI Tools 2025", category: "tech", viral_score: 95, heat_level: "fire", growth_stat: "+350%", tags: ["ai", "tools"], platform: "youtube", target_audience: "18-35" },
  { title: "Passive Income", category: "business", viral_score: 92, heat_level: "fire", growth_stat: "+280%", tags: ["money", "income"], platform: "tiktok", target_audience: "25-45" },
