function makeUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const items = $input.all();
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const now = new Date().toISOString();

const rows = items.map(item => ({
  id: makeUUID(),
  title: item.json.title,
  category: item.json.category || 'entertainment',
  viral_score: Number(item.json.viral_score) || 75,
  heat_level: String(item.json.heat_level || 'rising'),
  growth_stat: String(item.json.growth_stat || '+100%'),
  tags: Array.isArray(item.json.tags) ? item.json.tags : [],
  platform: String(item.json.platform || 'youtube'),
  target_audience: String(item.json.target_audience || '18-35'),
  active: true,
  updated_at: now
}));

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/trending_topics?active=eq.true',
    headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: { active: false },
    json: true
  });
} catch(e) { console.log('Deactivate error:', e.message); }

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/trending_topics',
    headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: rows,
    json: true
  });
} catch(e) { console.log('Insert error:', e.message); }

return rows.map(r => ({ json: r }));
